<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    background: #f4f5f7;
    color: #222;
    margin: 0;
    padding: 1.5rem;
  }
  main { max-width: 720px; margin: 0 auto; }
  h1 { font-size: 1.4rem; margin: 0 0 1rem; }
  section {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 1rem;
    margin-bottom: 1rem;
  }
  h2 { font-size: 1rem; margin: 0 0 .75rem; color: #444; }
  form .fields {
    display: flex;
    flex-wrap: wrap;
    gap: .6rem;
    align-items: flex-end;
  }
  label { display: flex; flex-direction: column; font-size: .8rem; gap: .2rem; color: #555; }
  input, select, button {
    font: inherit;
    padding: .4rem .5rem;
    border: 1px solid #bbb;
    border-radius: 5px;
  }
  input:focus, select:focus { outline: 2px solid #4a7cf7; outline-offset: 1px; }
  button {
    background: #2b6cb0;
    color: #fff;
    border: none;
    cursor: pointer;
    padding: .45rem .9rem;
  }
  button:hover { background: #245a94; }
  #form-error { color: #c0392b; font-size: .85rem; min-height: 1.2em; margin-top: .5rem; }
  .filters { display: flex; flex-wrap: wrap; gap: .6rem; align-items: flex-end; }
  #expense-list { margin-top: .5rem; }
  .expense {
    display: flex;
    align-items: center;
    gap: .75rem;
    padding: .45rem .3rem;
    border-bottom: 1px solid #eee;
  }
  .expense:last-child { border-bottom: none; }
  .exp-amount { font-weight: 600; min-width: 5.5em; text-align: right; font-variant-numeric: tabular-nums; }
  .exp-cat {
    background: #e8eef9;
    color: #2b4a7a;
    border-radius: 999px;
    padding: .1rem .6rem;
    font-size: .78rem;
    text-transform: capitalize;
  }
  .exp-date { font-size: .85rem; color: #555; min-width: 6.5em; }
  .exp-note { flex: 1; font-size: .85rem; color: #666; overflow-wrap: anywhere; }
  .exp-del {
    background: #e05252;
    padding: .25rem .55rem;
    font-size: .8rem;
    margin-left: auto;
  }
  .exp-del:hover { background: #c43b3b; }
  .totals { display: flex; flex-wrap: wrap; gap: .5rem 1.25rem; align-items: baseline; }
  #total { font-size: 1.25rem; font-weight: 700; font-variant-numeric: tabular-nums; }
  .cat-total {
    font-size: .85rem;
    color: #444;
    background: #f0f2f5;
    border-radius: 5px;
    padding: .2rem .55rem;
    text-transform: capitalize;
  }
  .empty { color: #888; font-size: .9rem; padding: .5rem .3rem; }
</style>
</head>
<body>
<main>
  <h1>Personal Expense Tracker</h1>

  <section>
    <h2>Add expense</h2>
    <form id="expense-form" novalidate>
      <div class="fields">
        <label>Amount
          <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
        </label>
        <label>Category
          <select id="category">
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </label>
        <label>Date
          <input type="date" id="date">
        </label>
        <label>Note (optional)
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </label>
        <button type="submit" id="add-expense">Add expense</button>
      </div>
      <div id="form-error" role="alert"></div>
    </form>
  </section>

  <section>
    <h2>Filters</h2>
    <div class="filters">
      <label>Category
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </label>
      <label>From
        <input type="date" id="filter-from">
      </label>
      <label>To
        <input type="date" id="filter-to">
      </label>
      <button type="button" id="clear-filters">Clear filters</button>
    </div>
  </section>

  <section>
    <h2>Summary (visible expenses)</h2>
    <div class="totals">
      <div>Total: <span id="total">0.00</span></div>
      <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
      <span class="cat-total" data-cat="transport">transport: 0.00</span>
      <span class="cat-total" data-cat="bills">bills: 0.00</span>
      <span class="cat-total" data-cat="fun">fun: 0.00</span>
    </div>
  </section>

  <section>
    <h2>Expenses</h2>
    <div id="expense-list"></div>
  </section>
</main>

<script>
(function () {
  'use strict';

  var STORAGE_KEY = 'expense-tracker-expenses';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  var form = document.getElementById('expense-form');
  var amountInput = document.getElementById('amount');
  var categoryInput = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var formError = document.getElementById('form-error');
  var listEl = document.getElementById('expense-list');
  var totalEl = document.getElementById('total');
  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');
  var clearFilters = document.getElementById('clear-filters');

  var expenses = loadExpenses();
  var nextId = expenses.reduce(function (m, e) { return Math.max(m, e.id); }, 0) + 1;

  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (e) {
        return e && typeof e.amount === 'number' && isFinite(e.amount) &&
               typeof e.category === 'string' && typeof e.date === 'string';
      });
    } catch (err) {
      return [];
    }
  }

  function saveExpenses() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) { /* storage unavailable; app keeps working in-memory */ }
  }

  function matchesFilters(exp) {
    var cat = filterCategory.value;
    if (cat !== 'all' && exp.category !== cat) return false;
    var from = filterFrom.value;
    var to = filterTo.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    listEl.innerHTML = '';
    var visible = expenses.filter(matchesFilters);

    // Newest first: by date descending, ties broken by insertion order (newest added first)
    var sorted = visible.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return b.id - a.id;
    });

    if (sorted.length === 0) {
      var empty = document.createElement('div');
      empty.className = 'empty';
      empty.textContent = expenses.length === 0
        ? 'No expenses yet. Add one above.'
        : 'No expenses match the current filters.';
      listEl.appendChild(empty);
    }

    sorted.forEach(function (exp) {
      var row = document.createElement('div');
      row.className = 'expense';

      var amt = document.createElement('span');
      amt.className = 'exp-amount';
      amt.textContent = exp.amount.toFixed(2);

      var cat = document.createElement('span');
      cat.className = 'exp-cat';
      cat.textContent = exp.category;

      var date = document.createElement('span');
      date.className = 'exp-date';
      date.textContent = exp.date;

      var note = document.createElement('span');
      note.className = 'exp-note';
      note.textContent = exp.note || '';

      var del = document.createElement('button');
      del.type = 'button';
      del.className = 'exp-del';
      del.textContent = 'Delete';
      del.addEventListener('click', function () {
        expenses = expenses.filter(function (e) { return e.id !== exp.id; });
        saveExpenses();
        render();
      });

      row.appendChild(amt);
      row.appendChild(cat);
      row.appendChild(date);
      row.appendChild(note);
      row.appendChild(del);
      listEl.appendChild(row);
    });

    var total = visible.reduce(function (sum, e) { return sum + e.amount; }, 0);
    totalEl.textContent = total.toFixed(2);

    CATEGORIES.forEach(function (c) {
      var catTotal = visible.reduce(function (sum, e) {
        return e.category === c ? sum + e.amount : sum;
      }, 0);
      var el = document.querySelector('.cat-total[data-cat="' + c + '"]');
      if (el) el.textContent = c + ': ' + catTotal.toFixed(2);
    });
  }

  form.addEventListener('submit', function (ev) {
    ev.preventDefault();

    var rawAmount = amountInput.value.trim();
    var amount = parseFloat(rawAmount);
    if (rawAmount === '' || isNaN(amount) || !isFinite(amount)) {
      formError.textContent = 'Please enter a valid numeric amount.';
      return;
    }
    if (amount <= 0) {
      formError.textContent = 'Amount must be greater than zero.';
      return;
    }
    if (!dateInput.value) {
      formError.textContent = 'Please choose a date.';
      return;
    }

    expenses.push({
      id: nextId++,
      amount: Math.round(amount * 100) / 100,
      category: categoryInput.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    });
    saveExpenses();

    formError.textContent = '';
    amountInput.value = '';
    noteInput.value = '';
    render();
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterFrom.addEventListener('input', render);
  filterTo.addEventListener('change', render);
  filterTo.addEventListener('input', render);

  clearFilters.addEventListener('click', function () {
    filterCategory.value = 'all';
    filterFrom.value = '';
    filterTo.value = '';
    render();
  });

  render();
})();
</script>
</body>
</html>
